queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?roomtype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRooms ?child ; p:hasHouses ?parent . } GROUP BY ?child }
  ?child p:roomType ?roomtype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Houses } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?address ?roomtype WHERE {
  ?houses a :Houses .
  ?houses_rooms a :Houses_Rooms .
  ?houses_rooms p:hasHouses ?houses .
  ?rooms a :Rooms .
  ?houses_rooms p:hasRooms ?rooms .
  ?houses p:address ?address .
  ?rooms p:roomType ?roomtype .
} }
  collective: { SELECT ?roomtype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRooms ?child ; p:hasHouses ?parent . } GROUP BY ?child }
  ?child p:roomType ?roomtype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Houses } }
  FILTER(?nf = ?total)
} }
}
